import jwt
import json
from datetime import datetime
from typing import Dict, Any, Optional, Tuple

def decode_jwt(token: str, secret: Optional[str] = None, verify: bool = False, 
               algorithms: list = None) -> Tuple[Dict[str, Any], Dict[str, Any]]:
    """
    Decode and optionally verify a JWT token for debugging purposes.
    
    Args:
        token: JWT token string
        secret: Secret key for verification (optional)
        verify: Whether to verify signature (default: False for debugging)
        algorithms: List of allowed algorithms (default: ['HS256', 'HS512', 'RS256'])
    
    Returns:
        Tuple of (header, payload) dictionaries
    """
    if algorithms is None:
        algorithms = ['HS256', 'HS512', 'HS384', 'RS256', 'RS384', 'RS512', 'ES256', 'ES384', 'ES512']
    
    try:
        # Decode header without verification
        header = jwt.get_unverified_header(token)
        
        if verify and secret:
            # Decode and verify
            payload = jwt.decode(token, secret, algorithms=algorithms)
        else:
            # Decode without verification for debugging
            payload = jwt.decode(token, options={"verify_signature": False}, algorithms=algorithms)
        
        return header, payload
    
    except jwt.ExpiredSignatureError:
        # Still decode for debugging even if expired
        header = jwt.get_unverified_header(token)
        payload = jwt.decode(token, options={"verify_signature": False, "verify_exp": False}, 
                           algorithms=algorithms)
        return header, payload
    except Exception as e:
        raise Exception(f"Error decoding JWT: {str(e)}")


def inspect_jwt(token: str, secret: Optional[str] = None, verify: bool = False) -> str:
    """
    Inspect JWT token and return formatted information for debugging.
    
    Args:
        token: JWT token string
        secret: Secret key for verification (optional)
        verify: Whether to verify signature (default: False)
    
    Returns:
        Formatted string with token details
    """
    try:
        header, payload = decode_jwt(token, secret, verify)
        
        output = []
        output.append("=" * 60)
        output.append("JWT TOKEN INSPECTION")
        output.append("=" * 60)
        
        # Header
        output.append("\nHEADER:")
        output.append(json.dumps(header, indent=2))
        
        # Payload
        output.append("\nPAYLOAD:")
        output.append(json.dumps(payload, indent=2))
        
        # Check expiration
        if 'exp' in payload:
            exp_time = datetime.fromtimestamp(payload['exp'])
            now = datetime.now()
            output.append(f"\nEXPIRATION:")
            output.append(f"  Expires at: {exp_time}")
            output.append(f"  Current time: {now}")
            if exp_time < now:
                output.append(f"  Status: EXPIRED ({now - exp_time} ago)")
            else:
                output.append(f"  Status: VALID (expires in {exp_time - now})")
        
        # Check issued at
        if 'iat' in payload:
            iat_time = datetime.fromtimestamp(payload['iat'])
            output.append(f"\nISSUED AT: {iat_time}")
        
        # Check not before
        if 'nbf' in payload:
            nbf_time = datetime.fromtimestamp(payload['nbf'])
            output.append(f"NOT BEFORE: {nbf_time}")
        
        # Verification status
        output.append(f"\nSIGNATURE VERIFICATION: {'ENABLED' if verify else 'DISABLED (Debug Mode)'}")
        if verify:
            output.append("  Status: VERIFIED")
        
        output.append("=" * 60)
        
        return "\n".join(output)
    
    except Exception as e:
        return f"Error inspecting JWT: {str(e)}"


def verify_jwt(token: str, secret: str, algorithms: list = None, 
               verify_exp: bool = True) -> Dict[str, Any]:
    """
    Verify JWT token with full validation.
    
    Args:
        token: JWT token string
        secret: Secret key for verification
        algorithms: List of allowed algorithms
        verify_exp: Whether to verify expiration (default: True)
    
    Returns:
        Decoded payload if verification succeeds
    """
    if algorithms is None:
        algorithms = ['HS256']
    
    options = {}
    if not verify_exp:
        options["verify_exp"] = False
    
    return jwt.decode(token, secret, algorithms=algorithms, options=options)


